const rawContent = $input.first().json.message?.content || $input.first().json.choices?.[0]?.message?.content || '{}';
let parsed = {};
try {
  const cleaned = rawContent.replace(/```json|```/g, '').trim();
  parsed = JSON.parse(cleaned);
} catch(e) {
  parsed = { intent: 'spending_query', start_date: null, end_date: null, person: null, category: null, common_only: null, comparison: null, group_by: null };
}
return [{ json: parsed }];

// =============================
// Date Engine
// =============================

const now = new Date();

function normalizeDate(date) {
  const d = new Date(date);
  if (isNaN(d)) return null;
  d.setHours(0,0,0,0);
  return d;
}

function getDateRange(timeReference) {

  switch (timeReference) {

    case "this_month":
      return {
        start: normalizeDate(new Date(now.getFullYear(), now.getMonth(), 1)),
        end: normalizeDate(now)
      };

    case "last_month":
      return {
        start: normalizeDate(new Date(now.getFullYear(), now.getMonth() - 1, 1)),
        end: normalizeDate(new Date(now.getFullYear(), now.getMonth(), 0))
      };

    case "this_year":
      return {
        start: normalizeDate(new Date(now.getFullYear(), 0, 1)),
        end: normalizeDate(now)
      };

    case "last_year":
      return {
        start: normalizeDate(new Date(now.getFullYear() - 1, 0, 1)),
        end: normalizeDate(new Date(now.getFullYear() - 1, 11, 31))
      };

    case "last_week":
      const day = now.getDay();
      const diffToMonday = (day + 6) % 7;

      const lastMonday = new Date(now);
      lastMonday.setDate(now.getDate() - diffToMonday - 7);

      const lastSunday = new Date(lastMonday);
      lastSunday.setDate(lastMonday.getDate() + 6);

      return {
        start: normalizeDate(lastMonday),
        end: normalizeDate(lastSunday)
      };

    case "this_week":
      const currentDay = now.getDay();
      const diff = (currentDay + 6) % 7;

      const monday = new Date(now);
      monday.setDate(now.getDate() - diff);

      return {
        start: normalizeDate(monday),
        end: normalizeDate(now)
      };

    default:
      return { start: null, end: null };
  }
}

function formatDate(date) {
  if (!date) return null;
  return date.toISOString().split('T')[0];
}

// =============================
// Retrieve Intent
// =============================

const intent = $('JS | Extract Intent JSON').first().json;
const edit3 = $('SET | Assemble Resolved Intent').first().json;

// IMPORTANT: overwrite values if edited
intent.person = edit3.person || intent.person;
intent.category = edit3.category || intent.category;

// =============================
// Load & Normalize Data
// =============================

const expenseItems = $('GS | Load Expenses').all().map(i => ({
  date: i.json.date,
  amount: parseFloat(i.json.amount) || 0,
  category: i.json.category?.toLowerCase() || null,
  description: i.json.description,
  common_expense: i.json.common_expense,
  person: i.json.Person?.toLowerCase() || null
}));

// =============================
// Date Handling
// =============================

let startDate = null;
let endDate = null;

if (intent.time_reference) {
  const range = getDateRange(intent.time_reference);
  startDate = range.start;
  endDate = range.end;
}

if (intent.explicit_start_date) {
  startDate = normalizeDate(intent.explicit_start_date);
}

if (intent.explicit_end_date) {
  endDate = normalizeDate(intent.explicit_end_date);
}

const formattedStart = formatDate(startDate);
const formattedEnd = formatDate(endDate);

// =============================
// Other Filters
// =============================

const filterPerson = intent.person ? intent.person.toLowerCase() : null;

const filterCategories = (() => {
  const c = intent.category;
  if (!c) return [];
  if (Array.isArray(c)) {
    return c.map(x => String(x).trim().toLowerCase()).filter(Boolean);
  }
  return [String(c).trim().toLowerCase()].filter(Boolean);
})();

const filterCommon = intent.common_only;
const groupBy = intent.group_by;

// =============================
// Apply Filters
// =============================

const filtered = expenseItems.filter(row => {

  if (!row.date) return false;

  const rowDate = normalizeDate(row.date);
  if (!rowDate) return false;

  if (startDate && rowDate < startDate) return false;
  if (endDate && rowDate > endDate) return false;

  if (filterPerson && row.person !== filterPerson) return false;

  if (filterCategories.length > 0) {
    if (!row.category) return false;
    if (!filterCategories.includes(row.category)) return false;
  }

  if (filterCommon !== null && filterCommon !== undefined) {

    const isCommon =
      String(row.common_expense).toLowerCase() === 'true' ||
      row.common_expense === true ||
      row.common_expense === 1;

    if (filterCommon && !isCommon) return false;
    if (!filterCommon && isCommon) return false;
  }

  return true;

});

// =============================
// Aggregations
// =============================

const total = filtered.reduce((sum, row) => sum + row.amount, 0);

// Category breakdown
let categoryBreakdown = null;

if (groupBy === "category") {

  const breakdown = {};

  filtered.forEach(row => {

    const cat = row.category || "uncategorized";

    breakdown[cat] = (breakdown[cat] || 0) + row.amount;

  });

  categoryBreakdown = breakdown;
}

// Person breakdown
let personBreakdown = null;

if (groupBy === "person") {

  const breakdown = {};

  filtered.forEach(row => {

    const person = row.person || "unknown";

    breakdown[person] = (breakdown[person] || 0) + row.amount;

  });

  personBreakdown = breakdown;
}

// =============================
// Return Result
// =============================

return [{
  json: {
    intent,
    total: Math.round(total * 100) / 100,
    count: filtered.length,
    categoryBreakdown,
    personBreakdown,
    period: {
      start: formattedStart,
      end: formattedEnd
    },
    filters: {
      person: intent.person,
      category: intent.category,
      common_only: intent.common_only
    }
  }
}];

const data = $input.first().json;
const filters = data.filters || {};
const period = data.period || {};

let lines = [];

// =============================
// Header
// =============================

lines.push('📊 *Expense Summary*');
lines.push('');

// =============================
// Period Display (NEW)
// =============================

if (period.start || period.end) {
  const from = period.start || 'Beginning';
  const to = period.end || 'Today';
  lines.push(`📅 Period: ${from} → ${to}`);
} else {
  lines.push(`📅 Period: All time`);
}

// =============================
// Applied filters
// =============================

if (filters.person) lines.push(`👤 Person: ${filters.person}`);
if (filters.category) lines.push(`🏷️ Category: ${filters.category}`);

if (filters.common_only !== null && filters.common_only !== undefined) {
  lines.push(`🔗 Common expenses only: ${filters.common_only ? 'Yes' : 'No'}`);
}

lines.push('');
lines.push(`💰 *Total: €${data.total.toFixed(2)}*`);
lines.push(`📝 Transactions: ${data.count}`);

// =============================
// Category breakdown
// =============================

if (data.categoryBreakdown) {
  lines.push('');
  lines.push('*By Category:*');

  const sorted = Object.entries(data.categoryBreakdown)
    .sort((a, b) => b[1] - a[1]);

  sorted.forEach(([cat, amt]) => {
    const pct = data.total > 0
      ? ((amt / data.total) * 100).toFixed(1)
      : 0;

    lines.push(`  • ${cat}: $${amt.toFixed(2)} (${pct}%)`);
  });
}

// =============================
// Person breakdown
// =============================

if (data.personBreakdown) {
  lines.push('');
  lines.push('*By Person:*');

  const sorted = Object.entries(data.personBreakdown)
    .sort((a, b) => b[1] - a[1]);

  sorted.forEach(([person, amt]) => {
    const pct = data.total > 0
      ? ((amt / data.total) * 100).toFixed(1)
      : 0;

    lines.push(`  • ${person}: $${amt.toFixed(2)} (${pct}%)`);
  });
}

// =============================
// Comparison placeholder
// =============================

if (data.comparison) {
  lines.push('');
  lines.push(`📈 Comparison: [Feature coming soon]`);
}

// =============================
// Empty state
// =============================

if (data.count === 0) {
  lines.push('');
  lines.push('_No expenses found for the given filters._');
}

return [{ json: { message: lines.join('\n') } }];

const items = $('AGG | Aggregate Category List').first().json.category;
if (!Array.isArray(items)) {
  throw new Error('Expected category to be an array');
}

const buttons = items.map(item => ([{
  text: String(item),
  callback_data: String(item)
}]));

return [{
  json: {
    inline_keyboard: buttons,
    resumeUrl: $execution.resumeUrl
  }
}];

