const items = $input.all();

const result = {};

for (const item of items) {
  for (const [key, value] of Object.entries(item.json)) {
    if (
      value !== undefined &&
      value !== null &&
      value !== "" &&
      value !== "undefined"
    ) {
      result[key] = value;
    }
  }
}

return [{
  json: result,
  pairedItem: { item: 0 }
}];
